/** Petshop Probe Slot v9 (audit: versions+cron+pricing meta) */
add_action('wp_loaded', function(){
  if ( ($_GET['ps_probe'] ?? '') !== 'ps2026' ) return;
  global $wpdb;
  $out = array('ts'=>gmdate('c'));
  $files = array(
    'petshop_xml_main' => WP_PLUGIN_DIR.'/petshop-xml/petshop-xml.php',
    'class_pricing' => WP_PLUGIN_DIR.'/petshop-xml/includes/class-pricing.php',
    'class_pricing_vf' => WP_PLUGIN_DIR.'/petshop-xml/includes/class-pricing-vf.php',
    'class_admin_ui' => WP_PLUGIN_DIR.'/petshop-xml/includes/class-admin-ui.php',
    'class_vf_import' => WP_PLUGIN_DIR.'/petshop-xml/includes/class-vf-import.php',
    'class_cost_resolver' => WP_PLUGIN_DIR.'/petshop-xml/includes/class-product-cost-resolver.php',
    'class_fulfillment' => WP_PLUGIN_DIR.'/petshop-xml/includes/class-fulfillment-source.php',
  );
  foreach($files as $k=>$f){
    if(!file_exists($f)){ $out['ver'][$k]='MISSING '.$f; continue; }
    $head = file_get_contents($f, false, null, 0, 1200);
    if(preg_match('/[vV]ersion[:\s]*([0-9]+\.[0-9]+(?:\.[0-9]+)?)/', $head, $m)){ $out['ver'][$k]=$m[1]; }
    elseif(preg_match('/v([0-9]+\.[0-9]+(?:\.[0-9]+)?)/', $head, $m)){ $out['ver'][$k]=$m[1]; }
    else { $out['ver'][$k]='NO_VER: '.substr(preg_replace('/\s+/',' ',$head),0,120); }
  }
  if(defined('PETSHOP_XML_VERSION')) $out['PETSHOP_XML_VERSION']=PETSHOP_XML_VERSION;
  $out['blog_public'] = get_option('blog_public');
  $pay = get_option('woocommerce_paysera_settings');
  if(is_array($pay)){ $out['paysera'] = array('enabled'=>$pay['enabled']??'?','test'=>$pay['test_mode']??($pay['test']??($pay['sandbox']??'?')),'keys'=>implode(',',array_keys($pay))); }
  $crons = _get_cron_array(); $cl=array();
  foreach($crons as $time=>$hooks){ foreach($hooks as $hook=>$ev){ if(stripos($hook,'import')!==false || stripos($hook,'petshop')!==false || stripos($hook,'pmxi')!==false || stripos($hook,'shortpixel')!==false){ $cl[]=gmdate('m-d H:i',$time).' '.$hook; } } }
  $out['cron']=array_slice($cl,0,25);
  $imports = $wpdb->get_results("SELECT id,name,last_activity FROM {$wpdb->prefix}pmxi_imports", ARRAY_A);
  $out['imports']=$imports;
  $q = function($sql) use ($wpdb){ return (int)$wpdb->get_var($sql); };
  $pm = $wpdb->postmeta; $p = $wpdb->posts;
  $out['meta_counts'] = array(
    'cost_price_filled' => $q("SELECT COUNT(DISTINCT post_id) FROM $pm WHERE meta_key='_cost_price' AND meta_value<>''"),
    'manual_override_yes' => $q("SELECT COUNT(DISTINCT post_id) FROM $pm WHERE meta_key='_manual_price_override' AND meta_value='yes'"),
    'zb_price_init' => $q("SELECT COUNT(DISTINCT post_id) FROM $pm WHERE meta_key='_zb_price_initialized' AND meta_value='yes'"),
    'vf_price_init' => $q("SELECT COUNT(DISTINCT post_id) FROM $pm WHERE meta_key='_vf_price_initialized'"),
    'zb_cost' => $q("SELECT COUNT(DISTINCT post_id) FROM $pm WHERE meta_key='_zb_cost' AND meta_value<>''"),
    'vf_qty' => $q("SELECT COUNT(DISTINCT post_id) FROM $pm WHERE meta_key='_vf_qty'"),
    'active_src_vf' => $q("SELECT COUNT(*) FROM $pm WHERE meta_key='_active_fulfillment_source' AND meta_value='vf_dropship'"),
    'active_src_zb' => $q("SELECT COUNT(*) FROM $pm WHERE meta_key='_active_fulfillment_source' AND meta_value='zb_dropship'"),
    'legacy_manuf_total' => $q("SELECT COUNT(DISTINCT post_id) FROM $pm WHERE meta_key='_legacy_manufacturer' AND meta_value<>''"),
  );
  $out['legacy_cost_missing'] = $q("SELECT COUNT(DISTINCT lm.post_id) FROM $pm lm INNER JOIN $p po ON po.ID=lm.post_id AND po.post_type='product' AND po.post_status IN ('publish','draft') LEFT JOIN $pm cp ON cp.post_id=lm.post_id AND cp.meta_key='_cost_price' AND cp.meta_value<>'' LEFT JOIN $pm zb ON zb.post_id=lm.post_id AND zb.meta_key='_zb_cost' AND zb.meta_value<>'' WHERE lm.meta_key='_legacy_manufacturer' AND lm.meta_value<>'' AND cp.post_id IS NULL AND zb.post_id IS NULL");
  header('Content-Type: application/json');
  echo wp_json_encode($out);
  exit;
}, 1);
